/**
 * Finds duplicate order IDs in a list.
 * Uses a single-pass hash map approach for O(n) time complexity,
 * ensuring the 1M-element performance requirement (AC3) is met.
 *
 * @param orderIds - Array of order ID strings to check for duplicates
 * @returns Array of IDs that appear more than once, each listed exactly once
 */
export function findDuplicateOrderIds(orderIds: string[]): string[] {
  const seen = new Set<string>();
  const duplicates = new Set<string>();

  for (const id of orderIds) {
    if (seen.has(id)) {
      duplicates.add(id);
    } else {
      seen.add(id);
    }
  }

  return Array.from(duplicates);
}

